	if err != nil {
		t.Fatalf("ReadFile types/auth.js: %v", err)
	}
	content := string(data)

	checks := []struct {
		desc   string
		needle string
	}{
		{"header", "AUTO-GENERATED BY VELD"},
		{"User typedef", "@typedef {Object} User"},
		{"optional field", "[bio]"},
		{"array field", "string[]"},
		{"enum typedef", "@typedef {'admin' | 'user' | 'guest'} Role"},
