	if err := e.Emit(minimalAST(), outDir, emitter.EmitOptions{}); err != nil {
		t.Fatalf("Emit() error: %v", err)
	}

	data, err := os.ReadFile(filepath.Join(outDir, "routes", "auth.routes.js"))
	if err != nil {
		t.Fatalf("ReadFile auth.routes.js: %v", err)
	}
	content := string(data)

	checks := []struct {
		desc   string
		needle string
	}{
		{"header", "AUTO-GENERATED BY VELD"},
		{"function declaration", "function authRouter("},
		{"post route", "router.post('/api/auth/login'"},
		{"get route", "router.get('/api/auth/me'"},
		{"delete route", "router.delete('/api/auth/logout'"},
		{"post 201 status", "res.status(201).json(result)"},
		{"delete 204 status", "res.status(204).end()"},
		{"try/catch", "} catch (err) {"},
		{"service call camelCase", "service.login("},
		{"module.exports", "module.exports"},
	}
	for _, c := range checks {
		if !strings.Contains(content, c.needle) {
			t.Errorf("auth.routes.js missing %s: want %q\ngot:\n%s", c.desc, c.needle, content)
		}
	}

	// Must NOT contain TypeScript syntax.
	if strings.Contains(content, ": any") {
		t.Error("auth.routes.js should not contain TypeScript type annotations")
	}
}

