		{"try/catch", "} catch (err) {"},
		{"service call camelCase", "service.login("},
		{"module.exports", "module.exports"},
	}
	for _, c := range checks {
		if !strings.Contains(content, c.needle) {
			t.Errorf("auth.routes.js missing %s: want %q\ngot:\n%s", c.desc, c.needle, content)
		}
	}

	// Must NOT contain TypeScript syntax.
	if strings.Contains(content, ": any") {
		t.Error("auth.routes.js should not contain TypeScript type annotations")
	}
}

